eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   ARTISTS: () => (/* binding */ ARTISTS),\n/* harmony export */   PRODUCTS: () => (/* binding */ PRODUCTS)\n/* harmony export */ });\nconst ARTISTS = [\n    {\n        slug: \"ellina-akimova\",\n        name: \"Ellina\",\n        surname: \"Akimova\",\n        initials: \"EA\",\n        role: \"Pianist & Composer\",\n        country: \"France / Russia\",\n        accent: \"#b8975a\",\n        bg: \"linear-gradient(145deg,#2a2218,#6b4828,#b8975a)\",\n        bio: \"Pianist and composer with Russian roots, Ellina Akimova worked at the Bolchoi from 1990 to 1995. She is a pianist accompanist at the Ballet School of the Paris National Opéra, at the CNSMDP, at the CND, and at the dance school of the conservatoire of the XVIIe district of Paris.\",\n        extended: \"Dance Accompaniment (La Danse Accompagnée) is a set of Music for Ballet Class CDs composed and interpreted by Ellina Akimova. This collection is a wonderful tool for ballet teachers. Volumes I, III and IV feature music for the entire ballet class; Volume II features music for adagio, divertissement and pas de deux.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Dance Accompaniment, Vol. I\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#2d2518,#7a5035)\"\n            },\n            {\n                title: \"Dance Accompaniment, Vol. II\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#201c14,#604530)\"\n            },\n            {\n                title: \"Dance Accompaniment, Vol. III\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#281e14,#7a5a38)\"\n            },\n            {\n                title: \"Dance Accompaniment, Vol. IV\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#2a2018,#906040)\"\n            },\n            {\n                title: \"Dance Accompaniment, Vol. V\",\n                type: \"CD · New\",\n                grad: \"linear-gradient(145deg,#2a2010,#b06040)\"\n            },\n            {\n                title: \"Camille — La Mouette\",\n                type: \"Classical · 2 Suites\",\n                grad: \"linear-gradient(145deg,#1e1a10,#6a5030)\"\n            }\n        ]\n    },\n    {\n        slug: \"marina-surgan\",\n        name: \"Marina\",\n        surname: \"Surgan\",\n        initials: \"MS\",\n        role: \"Pianist\",\n        country: \"Russia / France\",\n        accent: \"#4a8090\",\n        bg: \"linear-gradient(145deg,#1a2428,#2a5060,#4a8090)\",\n        bio: \"Classically trained in Moscow, Marina Surgan has been principal pianist for the Canada National Ballet School since 1986. She has four CDs and two Piano Score Books available.\",\n        extended: \"Born in the former Soviet Union and classically trained in Moscow, Marina immigrated to Toronto in 1975. She recorded her first CD, Marina Surgan Live, in December 2006, followed by 20 Greatest Classical Variations in June 2007, Marina Surgan Live 2 in 2009, and Marina Surgan Live 3 thereafter. Her original compositions were used in an episode of the reality TV show Battle of the Blades in September 2010.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Marina Surgan Live\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#1a2830,#3a6070)\"\n            },\n            {\n                title: \"Marina Surgan Live 2\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#1e2c38,#4a7080)\"\n            },\n            {\n                title: \"Marina Surgan Live 3\",\n                type: \"CD · New\",\n                grad: \"linear-gradient(145deg,#202e3a,#508090)\"\n            },\n            {\n                title: \"20 Greatest Classical Variations\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#161e22,#2a5060)\"\n            }\n        ]\n    },\n    {\n        slug: \"ayumi-hirusaki\",\n        name: \"Ayumi\",\n        surname: \"Hirusaki\",\n        initials: \"AH\",\n        role: \"Pianist & Composer\",\n        country: \"Japan\",\n        accent: \"#7a5090\",\n        bg: \"linear-gradient(145deg,#1a1428,#4a2a60,#7a5090)\",\n        bio: \"Main pianist at the National Opera of Tokyo, Ayumi Hirusaki is the pianist accompanist for the ballet classes and rehearsals. She worked at the Opera of Vienna in 2006 and has had the opportunity to work with Attilio Labis, Michaël Denard, Patrick Dupond, and Bertrand Barena, among others.\",\n        extended: \"Ayumi Hirusaki travels the world working with professors and dancers from Japan and Europe. She masters the repertoire and can improvise jazz as well as ballet music.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Music for Ballet Class 1\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#1a1428,#4a2860)\"\n            },\n            {\n                title: \"Music for Ballet Class 2\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#1e1830,#5a3068)\"\n            },\n            {\n                title: \"Music for Ballet Class 3\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#201a38,#603870)\"\n            },\n            {\n                title: \"Music for Ballet Class 4\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#221c40,#7a4878)\"\n            }\n        ]\n    },\n    {\n        slug: \"richard-davis\",\n        name: \"Richard\",\n        surname: \"Davis\",\n        initials: \"RD\",\n        role: \"Pianist & Composer\",\n        country: \"United States\",\n        accent: \"#6a5030\",\n        bg: \"linear-gradient(145deg,#1e1610,#5a3a1a,#6a5030)\",\n        bio: \"Born in California, Richard Davis has been pianist at the Ballet School of the Opera of Paris since 1994. He is also accompanist at the Paris Conservatory.\",\n        extended: \"Richard Davis brings his expertise from the dance community worldwide. His Music for Ballet Class CD includes works by Strauss, Gounod, Lehar, Bach, and Mozart.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Music for Ballet Class\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#201810,#6a4820)\"\n            }\n        ]\n    },\n    {\n        slug: \"bertrand-barena\",\n        name: \"Bertrand\",\n        surname: \"Barena\",\n        initials: \"BB\",\n        role: \"Ballet Professor\",\n        country: \"France\",\n        accent: \"#7a6040\",\n        bg: \"linear-gradient(145deg,#1a1610,#4a3820,#7a6040)\",\n        bio: \"Professor at the Ballet School of the Opera of Paris, Bertrand Barena's pedagogy has been inspired by Serge Golovine and Claude Bessy.\",\n        extended: \"Bertrand Barena collaborated with Ellina Akimova and Tristan Lofficial on the Floor Barre CD. He has worked with Ayumi Hirusaki and many of the leading artists in the Mediaphorie catalogue.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Floor Barre — Piano Improvisations\",\n                type: \"CD · with T. Lofficial\",\n                grad: \"linear-gradient(145deg,#1a1610,#4a3820)\"\n            }\n        ]\n    },\n    {\n        slug: \"christopher-hobson\",\n        name: \"Christopher\",\n        surname: \"Hobson\",\n        initials: \"CH\",\n        role: \"Pianist & Composer\",\n        country: \"United Kingdom\",\n        accent: \"#508070\",\n        bg: \"linear-gradient(145deg,#101a18,#284840,#508070)\",\n        bio: \"Pianist and composer who had the privilege to work with many world renowned choreographers and directors, including Gillian Lynne, Mark Godden, and David Nixon, on productions including Nixon's Nutcracker and Swan Lake.\",\n        extended: \"Christopher started piano lessons at the age of 4 and trained at the Royal Northern College of Music Junior School and Chetham's School of Music, studying classical piano with Peter Lawson and jazz piano with Les Chisnall. He has worked at Northern School of Contemporary Dance, Elmhurst School for Dance, Liverpool Institute for Performing Arts, and Central School of Ballet, among others.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Modern Ballet Studio Melodies, Vol. 1\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#101a18,#284840)\"\n            },\n            {\n                title: \"Modern Ballet Studio Melodies, Vol. 2\",\n                type: \"CD\",\n                grad: \"linear-gradient(145deg,#142020,#305850)\"\n            }\n        ]\n    },\n    {\n        slug: \"tristan-lofficial\",\n        name: \"Tristan\",\n        surname: \"Lofficial\",\n        initials: \"TL\",\n        role: \"Pianist & Composer\",\n        country: \"France\",\n        accent: \"#6060a0\",\n        bg: \"linear-gradient(145deg,#101028,#303060,#6060a0)\",\n        bio: \"Jazzman, composer and pianist, Tristan Lofficial is pianist accompanist at the Paris Opéra. Born in Saint-Louis of Senegal in 1968, he resides in Paris where he leads a career as pianist improviser and performer.\",\n        extended: \"Tristan Lofficial has been dance accompanist at the Centre national de danse contemporaine, then at the Opéra national de Paris and the Conservatoire national supérieur de musique et danse de Paris between 2005 and 2019. He has participated in numerous workshops, residencies and tours with the Tanztheater Wuppertal, the Ballet du Capitole de Toulouse, and many others.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Floor Barre — Piano Improvisations\",\n                type: \"CD · with B. Barena\",\n                grad: \"linear-gradient(145deg,#101028,#303060)\"\n            }\n        ]\n    },\n    {\n        slug: \"elisabeth-maurin\",\n        name: \"Elisabeth\",\n        surname: \"Maurin\",\n        initials: \"EM\",\n        role: \"Ballet Professor & Étoile\",\n        country: \"France\",\n        accent: \"#906080\",\n        bg: \"linear-gradient(145deg,#201018,#602040,#906080)\",\n        bio: \"Ballet Professor and former Étoile, Elisabeth Maurin collaborated with Ellina Akimova in 2011 to create Volume V of the Dance Accompaniment collection — a complete course for professional dancers.\",\n        extended: \"In 2011, Elisabeth Maurin and Ellina Akimova created together Volume V of the Dance Accompaniment collection, covering barre, centre, pointes, and men's exercises.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Dance Accompaniment, Vol. V\",\n                type: \"CD · with E. Akimova\",\n                grad: \"linear-gradient(145deg,#2a2010,#b06040)\"\n            }\n        ]\n    },\n    {\n        slug: \"fe-de-mikhnevitch\",\n        name: \"F.E.\",\n        surname: \"de Mikhnevitch\",\n        initials: \"FM\",\n        role: \"Ballet Professor\",\n        country: \"France\",\n        accent: \"#708050\",\n        bg: \"linear-gradient(145deg,#141810,#384020,#708050)\",\n        bio: \"Ballet Professor and former dancer at the Opera of Paris, Franciska-Élisabeth de Mikhnevitch collaborated with Ellina Akimova in 2007 to create Volume IV of the Dance Accompaniment collection.\",\n        extended: \"In 2007, Franciska-Élisabeth de Mikhnevitch and Ellina Akimova created together Volume IV of the Dance Accompaniment collection — a complete course for professional dancers covering barre, centre, pointes, and men's exercises.\",\n        quote: \"\",\n        albums: [\n            {\n                title: \"Dance Accompaniment, Vol. IV\",\n                type: \"CD · with E. Akimova\",\n                grad: \"linear-gradient(145deg,#2a2018,#906040)\"\n            }\n        ]\n    }\n];\nconst PRODUCTS = [\n    {\n        slug: \"dance-accompaniment-v\",\n        title: \"Dance Accompaniment, Vol. V\",\n        artist: \"Ellina Akimova\",\n        artistSlug: \"ellina-akimova\",\n        type: \"Ballet Class CD\",\n        price: 22,\n        grad: \"linear-gradient(145deg,#2a2010,#b06040)\",\n        isNew: true,\n        formats: [\n            \"CD\",\n            \"MP3\"\n        ],\n        tracks: [\n            \"Battements Tendus — Waltz\",\n            \"Dégagés — Mazurka\",\n            \"Ronds de Jambe — Adagio\",\n            \"Fondus — Slow Waltz\",\n            \"Frappés — Polka\",\n            \"Grand Battement — March\",\n            \"Port de Bras — Nocturne\",\n            \"Pirouettes — Allegro\",\n            \"Grand Allegro — Valse Brillante\",\n            \"Reverence — Adagio\"\n        ],\n        desc: \"The fifth and latest volume in Ellina Akimova's celebrated Dance Accompaniment series. Fresh compositions and arrangements bring the same hallmarks — musical sensitivity, perfect tempi, and an intimate understanding of the dancer's needs.\"\n    },\n    {\n        slug: \"marina-surgan-live3\",\n        title: \"Marina Surgan Live 3\",\n        artist: \"Marina Surgan\",\n        artistSlug: \"marina-surgan\",\n        type: \"Ballet Class CD\",\n        price: 22,\n        grad: \"linear-gradient(145deg,#202e3a,#508090)\",\n        isNew: true,\n        formats: [\n            \"CD\",\n            \"MP3\",\n            \"Sheet Music\"\n        ],\n        tracks: [\n            \"Opening March — Pliés\",\n            \"Battements — Vivace\",\n            \"Adagio — Ronds de Jambe\",\n            \"Fondus Lyriques\",\n            \"Développés — Largo\",\n            \"Grand Battement — Allegro\",\n            \"Centre Adagio\",\n            \"Allegro I\",\n            \"Grand Allegro\",\n            \"Variations — Coda\"\n        ],\n        desc: \"The third and most celebrated volume of Marina Surgan's Live series. Recorded in a single session full of spontaneity, this album captures Marina at the height of her artistry — bold, rhythmically precise, deeply musical.\"\n    },\n    {\n        slug: \"camille-la-mouette\",\n        title: \"Camille — La Mouette\",\n        artist: \"Ellina Akimova\",\n        artistSlug: \"ellina-akimova\",\n        type: \"Classical Music\",\n        price: 22,\n        grad: \"linear-gradient(145deg,#1e1a10,#6a5030)\",\n        formats: [\n            \"CD\",\n            \"MP3\"\n        ],\n        tracks: [\n            \"La Mouette — Prologue\",\n            \"L'Été sur le Lac\",\n            \"Danse de la Mouette\",\n            \"La Valse (Camille)\",\n            \"Camille — Prélude\",\n            \"Nocturne du Soir\",\n            \"Scène Finale\"\n        ],\n        desc: \"Two suites for solo piano composed and performed by Ellina Akimova. Inspired by Chekhov and the French countryside, moving between lyricism and dramatic intensity with natural ease.\"\n    },\n    {\n        slug: \"dance-accompaniment-iv\",\n        title: \"Dance Accompaniment, Vol. IV\",\n        artist: \"Ellina Akimova\",\n        artistSlug: \"ellina-akimova\",\n        type: \"Ballet Class CD\",\n        price: 22,\n        grad: \"linear-gradient(145deg,#2a2018,#906040)\",\n        formats: [\n            \"CD\",\n            \"MP3\"\n        ],\n        tracks: [\n            \"Pliés — Largo\",\n            \"Tendus — Moderato\",\n            \"Dégagés — Vivace\",\n            \"Ronds de Jambe\",\n            \"Adagio Central\",\n            \"Grand Battement\",\n            \"Centre Work I\",\n            \"Centre Work II\",\n            \"Allegro\",\n            \"Reverence\"\n        ],\n        desc: \"Volume IV continues the Dance Accompaniment tradition with a fresh collection of compositions designed specifically for the structure and demands of the classical ballet class.\"\n    },\n    {\n        slug: \"the-snow-queen\",\n        title: \"The Snow Queen\",\n        artist: \"Mediaphorie\",\n        artistSlug: null,\n        type: \"Children's Music\",\n        price: 20,\n        grad: \"linear-gradient(145deg,#182030,#3a5070)\",\n        formats: [\n            \"CD\"\n        ],\n        tracks: [\n            \"Once Upon a Winter\",\n            \"The Snow Queen's Theme\",\n            \"Snowflakes Dance\",\n            \"The Frozen Forest\",\n            \"Kay and Gerda\",\n            \"Mirror of Ice\",\n            \"The Robber Girl\",\n            \"Journey North\",\n            \"The Queen's Palace\",\n            \"Home Again\"\n        ],\n        desc: \"A magical musical journey for young dancers. The Snow Queen brings the Hans Christian Andersen fairy tale to life through enchanting piano music perfect for children's ballet classes and story-dance sessions.\"\n    },\n    {\n        slug: \"piano-scores-unlimited\",\n        title: \"Piano Scores Unlimited\",\n        artist: \"Various Artists\",\n        artistSlug: null,\n        type: \"Digital Score Collection\",\n        price: 45,\n        grad: \"linear-gradient(145deg,#1a2428,#4a6070)\",\n        formats: [\n            \"Digital Download\"\n        ],\n        tracks: [],\n        desc: \"A comprehensive digital collection of piano scores from across the Mediaphorie catalogue. Ideal for accompanists who want instant access to a wide range of exercises and compositions.\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(pages-dir-node)/./src/lib/data.js\n");

